input.pageFunction:
/**
 * Scrape one Amazon product page for:
 *  • Title
 *  • “About this item” bullet points
 *  • Long product-description text
 *  • Visible reviews (rating, title, date, body, reviewer name)
 *
 * NOTE – selectors point at the exact markup snippets you provided.
 */
async function pageFunction (context) {
    const $ = context.jQuery;

    /* ---------- Helpers ---------- */
    const clean = txt => txt.replace(/\s+/g, ' ').trim();

    /* ---------- TITLE ---------- */
    // <span id="productTitle">…</span>
    const title = clean($('#productTitle').first().text());

    /* ---------- BULLET POINTS ---------- */
    // <div id="feature-bullets"> … <ul><li><span class="a-list-item">…</span></li> … </ul>
    const bulletPoints = $('#feature-bullets ul li span.a-list-item')
        .map((_, el) => clean($(el).text()))
        .get();

    /* ---------- PRODUCT DESCRIPTION ---------- */
    //
    // Amazon sometimes renders the same text in different containers,
    // so grab whichever exists and normalise <br> → \n so the text
    // is readable when returned as plain text.
    //
    let descHTML = $('#productDescription').html() ||
                   $('#productDescription_feature_div').html() ||
                   '';
    // Replace <br> with line-break text so we don’t lose paragraphs
    descHTML = descHTML.replace(/<br\s*\/?>/gi, '\n');
    // Strip all tags, squash whitespace
    const description = clean($('<div>').html(descHTML).text());

    /* ---------- REVIEWS ---------- */
    //
    // We stay inside the list <li data-hook="review"> you pasted.
    //
    const reviews = [];
    $('li[data-hook="review"]').each((_, el) => {
        const $rev = $(el);

        /* star rating “4.0 out of 5 stars” → 4.0 */
        const ratingTxt = $rev.find('i[data-hook="review-star-rating"] span')
                              .first().text();
        const rating = parseFloat((ratingTxt.match(/[\d.]+/) || [null])[0]);

        const reviewTitle = clean(
            $rev.find('a[data-hook="review-title"] span').first().text()
        );

        const reviewDate  = clean(
            $rev.find('span[data-hook="review-date"]').first().text()
        );

        // Body can live in two places (collapsed vs. expanded)
        let bodyEl = $rev.find('span[data-hook="review-body"]')
                         .first();
        if (!bodyEl.length) {
            bodyEl = $rev.find('div[data-hook="review-collapsed"]')
                         .first();
        }
        const reviewBody = clean(bodyEl.text());

        const reviewer   = clean(
            $rev.find('span.a-profile-name').first().text()
        );

        reviews.push({ rating, reviewTitle, reviewDate, reviewBody, reviewer });
    });

    /* ---------- FINAL SHAPE ---------- */
    const fixturesInfo = [{
        title,
        bulletPoints,   // array<string>
        description,    // string
        reviews         // array<object>
    }];

    return {
        return: {
            url: context.request.url,
            fixturesInfo
        }
    };
}

